import java.util.Scanner;

public class Main {

	public static void main(String[] args) {
		// Create a Scanner object to read input from the console
		Scanner sc = new Scanner(System.in);

		// Read three integers from the user input
		int A = sc.nextInt();
		int B = sc.nextInt();
		int C = sc.nextInt();

		// Initialize a counter to track the number of conditions met
		int count = 0;

		// Check if A is either 5 or 7
		if(A == 5 || A == 7) {
			count++; // Increment count if condition is true
		}

		// If A is 7, check if B is 5
		if(A == 7) {
			if(B == 5) {
				count++; // Increment count if condition is true
			}
		} 
		// If A is 5, check if B is either 5 or 7
		else if(A == 5) {
			if(B == 5 || B == 7) {
				count++; // Increment count if condition is true
			}
		}

		// Check combinations of A, B, and C to increment count
		if(A == 7 && B == 5) {
			if(C == 5) {
				count++; // Increment count if condition is true
			}
		} else if(A == 5 && B == 7) {
			if(C == 5) {
				count++; // Increment count if condition is true
			}
		} else if(A == 5 && B == 5) {
			if(C == 7) {
				count++; // Increment count if condition is true
			}
		}

		// Check if all three conditions are met
		if(count == 3) {
			System.out.println("YES"); // Print "YES" if count is 3
		} else {
			System.out.println("NO"); // Print "NO" otherwise
		}
	}
}

