		BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
		String buffer; // Variable to store each line of input
		boolean first = true; // Flag to determine if the current line is the first line of a pair
		int amount = 0; // Variable to store the number of integers to read from the second line
		List<Integer> list = new ArrayList<Integer>(); // List to store the integers from the second line

		try {
			// Continuously read lines from input until there are no more lines
			while ((buffer = reader.readLine()) != null) {
				if (first) {
					// If it's the first line of a pair, parse the number of integers to read
					first = false; // Set the flag to false indicating the next line is the second line
					amount = Integer.valueOf(buffer.substring(0, buffer.indexOf(" ") == -1 ? buffer.length() : buffer.indexOf(" ")));
					// Initialize a new list to store integers for the current pair of lines
					list = new ArrayList<Integer>();
				} else {
					// If it's the second line of a pair
					first = true; // Reset the flag for the next pair of lines
					// Loop to extract integers from the line based on the amount specified
					for (int i = 0; i < amount; i++) {
						// Add each integer to the list
						list.add(Integer.valueOf(buffer.substring(0, buffer.indexOf(" ") == -1 ? buffer.length() : buffer.indexOf(" "))));
						// Remove the processed integer from the buffer
						buffer = buffer.substring(buffer.indexOf(" ") + 1);
