import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {
    public static void main(String[] args) {

        // Declare variables to hold year, month, and day
        int y, m, d;

        // Create a BufferedReader to read input from the console
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        try {
            // Read a line of input from the user
            String line = br.readLine();

            // Split the input line by "/" to separate year, month, and day
            String[] tbcConnection = line.split("/");
            int cnt = 0; // Counter to track the position in the date (year, month, day)
            int ok_cnt = 0; // Counter to track if the date is before 2019
            int end_flg = 0; // Flag to indicate if the date is determined to be "TBD"

            // Iterate over each part of the date (year, month, day)
            for (String tbc : tbcConnection) {
                if (end_flg == 0) { // Only process if the date is not yet determined as "TBD"
                    // Check if the year is before 2019 and it's the first part (year)
                    if (Integer.parseInt(tbc) < 2019 && cnt == 0) {
                        ok_cnt++; // Increment ok_cnt if the year is before 2019
                    }

                    cnt++; // Increment the counter to move to the next part of the date

                    // Check if the year is after 2019 and it's the first part (year)
                    if (Integer.parseInt(tbc) > 2019 && cnt == 1 && ok_cnt == 0) {
                        System.out.println("TBD"); // Print "TBD" if the year is after 2019
                        end_flg++; // Set the flag to indicate the date is "TBD"
                    } 
                    // Check if the month is after April and it's the second part (month)
                    else if (Integer.parseInt(tbc) > 4 && cnt == 2 && ok_cnt == 0) {
                        System.out.println("TBD"); // Print "TBD" if the month is after April
                        end_flg++; // Set the flag to indicate the date is "TBD"
                    } 
                    // Check if the day is after the 30th and it's the third part (day)
                    else if (Integer.parseInt(tbc) > 30 && cnt == 3 && ok_cnt == 0) {
                        System.out.println("TBD"); // Print "TBD" if the day is after the 30th
                        end_flg++; // Set the flag to indicate the date is "TBD"
                    }
                }
            }

            // If the date is not determined as "TBD", print "Heisei"
            if (end_flg == 0) {
                System.out.println("Heisei");
            } else {
                System.out.println(); // Print a new line if the date was "TBD"
            }

        } catch (IOException e) {
            // Print the exception if an I/O error occurs
            System.out.println(e);
        }
    }
}

